def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0.0
        additive = 0.0
        decay = 1.0
        penalty = 0.0
        for j in range(1, 15):
            if j % 3 == 0:
                decay *= 0.85
            if ratio < (0.04 * j):
                increase = (j ** 2) * np.exp(-ratio) * decay
                score += increase
                if cap % (j + 2) == 0:
                    score += np.sqrt(j) * np.log1p(cap)
                else:
                    score -= (j ** 0.75) * np.cos(ratio * j)
            else:
                decrease = j * np.exp(-0.5 * ratio * j) * decay / (j + 2)
                score -= decrease
                if (cap + j) % 4 == 0:
                    score += np.sin(ratio * j) * (j ** 0.8)
                else:
                    score -= np.tanh(ratio / (j + 1)) * j
            if j % 2 == 0:
                additive += np.arctan(score / (j + 0.5))
            else:
                additive -= np.tanh(score / (j + 1))
            if j in [5,10,14]:
                penalty += np.abs(np.sin(score * j))
        for k in range(1, 7):
            residual = cap - item * k
            if residual > 0:
                if residual % (k + 1) == 0:
                    score += np.log1p(residual) / (k + 0.7)
                else:
                    score -= (residual ** 0.3) / (k + 1.2)
                if residual % 2 == 0:
                    additive += np.sqrt(residual) / (k + 0.5)
                else:
                    additive -= np.cbrt(residual) / (k + 1)
            else:
                abs_res = abs(residual)
                if abs_res > item:
                    penalty += abs_res * 0.2 * k
                else:
                    penalty -= abs_res * 0.1
        final_value = (score + additive - penalty) / (cap + 0.1)
        if final_value > 0:
            priorities[i] = -final_value * np.exp(-1.2 * ratio) * (1 + np.sin(cap))
        else:
            priorities[i] = -final_value * (np.log1p(cap + 1) + np.sqrt(item + 1)) * (1 + np.cos(ratio))
    return priorities
